{
  "title": "सिस्टम प्रॉम्प्ट की भूमिका",
  "group": "बुनियादी बातें",
  "options": [
    {
      "text": "यह पहले प्रोसेस किया जाता है और उपयोगकर्ता संदेशों की तुलना में अधिक वजन रखता है"
    },
    {
      "text": "यह उपयोगकर्ता संदेश के समान है लेकिन अलग तरीके से प्रदर्शित होता है"
    },
    {
      "text": "यह केवल API कॉल्स के लिए उपयोग किया जाता है, चैट इंटरफ़ेस के लिए नहीं"
    },
    {
      "text": "यह सत्रों के बीच दीर्घकालिक स्मृति के रूप में बना रहता है"
    }
  ],
  "questionProse": [
    "संदेश एरे में `system` भूमिका और `user` भूमिका का उपयोग करने का व्यावहारिक प्रभाव क्या है?"
  ],
  "explanationProse": [
    "`system` भूमिका को उच्च प्राथमिकता वाले निर्देशों के रूप में प्रोसेस किया जाता है। मॉडल्स को उपयोगकर्ता संदेशों की तुलना में इसे अधिक वजन देने के लिए प्रशिक्षित किया जाता है — यह \"what the developer said\" और \"what the user said\" के बीच की वास्तुशिल्पीय सीमा है।\n\n    यह जादू नहीं है। यह गारंटी नहीं देता कि मॉडल विरोधी उपयोगकर्ता निर्देशों को अनदेखा कर देगा (देखें: prompt injection)। लेकिन यह मॉडल की आपके निर्देशों का पालन करने की प्रवृत्ति को सार्थक रूप से बढ़ाता है, विशेष रूप से उन मॉडलों में जो निर्देश‑अनुपालन में मजबूत हैं।\n\n    व्यावहारिक रूप से: अपनी पर्सोना, नियम, और व्यवहारिक प्रतिबंध `system` में रखें। प्राप्त संदर्भ और उपयोगकर्ता डेटा `user` में रखें। उपयोगकर्ता‑नियंत्रित इनपुट कभी भी `system` में न रखें।"
  ]
}
